import React, { useState, useEffect } from 'react';
import {
  Bot, ArrowLeft, Activity, Eye, Clock, AlertTriangle, CheckCircle2,
  XCircle, ToggleLeft, ToggleRight, TrendingUp, FileText, RefreshCw,
  Shield, Zap, BarChart3, Globe, ChevronDown, ChevronUp, Bell
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area, CartesianGrid } from 'recharts';
import { useTranslation } from '../i18n';

// Activity chart data (24h)
const HOURLY_DATA = [12, 18, 8, 5, 3, 2, 4, 15, 28, 42, 38, 45, 52, 48, 55, 60, 58, 50, 42, 35, 28, 22, 18, 15];

const HOURLY_CHART_DATA = HOURLY_DATA.map((value, i) => ({
  hour: `${String(i).padStart(2, '0')}h`,
  crawls: value,
}));

// Mini sparkline data generator for individual bot trend lines
const generateSparklineData = (crawlsWeek: number, trend: number) => {
  const points = 7;
  const data = [];
  const base = crawlsWeek / points;
  for (let i = 0; i < points; i++) {
    const trendFactor = trend >= 0
      ? 1 + (trend / 100) * (i / points)
      : 1 + (trend / 100) * (i / points);
    const noise = 0.7 + Math.random() * 0.6;
    data.push({
      day: `J${i + 1}`,
      crawls: Math.round(base * trendFactor * noise),
    });
  }
  return data;
};

